package co.edu.elecciones.config; import co.edu.elecciones.commons.dto.ApiResponse; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestControllerAdvice public class GlobalExceptionHandler { @ExceptionHandler(Exception.class) public ResponseEntity<ApiResponse<Void>> ex(Exception e){ return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(ApiResponse.error(e.getMessage())); } }
